#!/usr/bin/env node
/**
 * Field-mapping regression test.
 *
 * The goldens in scripts/fixtures/field-mapping/ were generated by running
 * the ORIGINAL hand-written intake parser (src/lib/intake-webhook.ts as of
 * f35e557) over the two fixtures. This proves the declarative mapping
 * (content/admin/intake-mapping.json) + the engine (packages/field-mapping)
 * reproduce that parser's behavior exactly: config, contact, flags, notes
 * (text and order), unmapped list, context bundle, and the mapping report.
 *
 * The single allowed difference: config.$comment (the engine's provenance
 * string replaced the old "Google Form webhook" wording).
 *
 * Run: node scripts/test-field-mapping.mjs
 */
import fs from 'node:fs';
import path from 'node:path';
import assert from 'node:assert';
import { fileURLToPath } from 'node:url';
import { runMapping, validateMapping } from '../packages/field-mapping/index.mjs';

const REPO = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const FIXTURES = path.join(REPO, 'scripts', 'fixtures', 'field-mapping');
const loadJson = (p) => JSON.parse(fs.readFileSync(p, 'utf-8'));

const mapping = loadJson(path.join(REPO, 'content', 'admin', 'intake-mapping.json'));
let failures = 0;
const check = (name, fn) => {
  try {
    fn();
    console.log(`  ok    ${name}`);
  } catch (err) {
    failures++;
    console.error(`  FAIL  ${name}`);
    console.error(String(err.message).split('\n').map((l) => `        ${l}`).join('\n'));
  }
};

console.log('validateMapping:');
check('deneb4 intake mapping is valid', () => {
  const v = validateMapping(mapping);
  assert.deepStrictEqual(v.errors, []);
  assert.strictEqual(v.ok, true);
});
check('catches broken mappings (bad regex, bad target, forward ref, dup id)', () => {
  const v = validateMapping({
    format: 'stardrive-field-mapping/v1',
    fields: [
      { id: 'a', source: { code: 'Q1', hint: '(' } },
      { id: 'a', source: { code: 'Q2' }, target: 'bogus.path' },
      { id: 'b', table: { inputs: ['zzz'], target: 'config.x', rules: [], default: '' } },
      { id: 'c', source: { code: 'Q3' }, transform: ['explode'] },
    ],
  });
  assert.strictEqual(v.ok, false);
  assert.strictEqual(v.errors.length >= 4, true);
});

console.log('golden parity (engine + mapping vs the original hand-written parser):');
for (const name of ['rich', 'sparse']) {
  check(`${name} fixture`, () => {
    const answers = loadJson(path.join(FIXTURES, `${name}.json`));
    delete answers.$comment;
    const golden = loadJson(path.join(FIXTURES, `golden-${name}.json`));
    const got = runMapping(mapping, answers);

    // The one sanctioned difference: the provenance string.
    const expectedConfig = {
      ...golden.config,
      $comment: 'd4-site-builder format. Proposed by the intake field-mapping engine; review before building.',
    };
    assert.deepStrictEqual(got.config, expectedConfig, 'config');
    assert.deepStrictEqual(got.contact, golden.clientContact, 'contact');
    assert.deepStrictEqual(got.flags, golden.flags, 'flags');
    assert.deepStrictEqual(got.notes, golden.notes, 'notes');
    assert.deepStrictEqual(got.unmapped, golden.unmapped, 'unmapped');
    assert.deepStrictEqual(got.context, golden.context, 'context');
    assert.deepStrictEqual(got.mapReport, golden.mapReport, 'mapReport');
  });
}

if (failures) {
  console.error(`\n${failures} check(s) FAILED.`);
  process.exit(1);
}
console.log('\nAll field-mapping checks passed.');
